// Enhanced app.js with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');

const app = express();

// ============= SECURITY MIDDLEWARE =============

// Set security HTTP headers
app.use(helmet());

// Remove X-Powered-By header
app.disable('x-powered-by');

// Body parser with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});

app.use(limiter);

// ============= INPUT VALIDATION HELPER =============

const validateEmail = (email) => {
  if (!email || typeof email !== 'string') return false;
  return validator.isEmail(email);
};

// ============= ROUTES =============

app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    res.status(500).json({ 
      error: 'Internal server error' 
    });
  }
});

app.get('/users', (req, res) => {
  try {
    // Validate query parameters
    const { limit, offset } = req.query;

    // Sanitize and validate pagination params
    const parsedLimit = parseInt(limit) || 10;
    const parsedOffset = parseInt(offset) || 0;

    // Enforce reasonable bounds
    if (parsedLimit < 1 || parsedLimit > 100) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter' 
      });
    }

    if (parsedOffset < 0) {
      return res.status(400).json({ 
        error: 'Invalid offset parameter' 
      });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Validate data integrity before returning
    const validatedUsers = users
      .slice(parsedOffset, parsedOffset + parsedLimit)
      .filter(user => 
        user.id && 
        typeof user.name === 'string' && 
        validateEmail(user.email)
      );

    res.json({
      data: validatedUsers,
      total: users.length,
      limit: parsedLimit,
      offset: parsedOffset
    });
  } catch (error) {
    console.error('Error in /users endpoint:', error);
    res.status(500).json({ 
      error: 'Internal server error' 
    });
  }
});

// ============= 404 HANDLER =============

app.use((req, res) => {
  res.status(404).json({ 
    error: 'Not Found' 
  });
});

// ============= GLOBAL ERROR HANDLER =============

app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose internal error details to client
  res.status(err.status || 500).json({
    error: err.status === 400 ? err.message : 'Internal server error'
  });
});

// ============= SERVER STARTUP =============

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

module.exports = app;
```

