```javascript
// Enhanced app.js with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');
const validator = require('validator');

const app = express();

// ============ SECURITY MIDDLEWARE ============

// Add security headers
app.use(helmet());

// Logging middleware
app.use(morgan('combined'));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// Parse JSON with size limit
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// ============ INPUT VALIDATION ============

// Middleware to sanitize and validate input
const validateUserInput = (req, res, next) => {
  try {
    // Validate query parameters if present
    if (req.query && Object.keys(req.query).length > 0) {
      for (const [key, value] of Object.entries(req.query)) {
        // Basic validation - reject suspicious patterns
        if (typeof value === 'string' && value.length > 1000) {
          return res.status(400).json({ error: 'Invalid input: parameter too long' });
        }
      }
    }
    next();
  } catch (error) {
    res.status(400).json({ error: 'Invalid request format' });
  }
};

app.use(validateUserInput);

// ============ ROUTES ============

app.get('/health', (req, res) => {
  try {
    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/users', (req, res) => {
  try {
    // Validate optional query parameters
    const { limit } = req.query;

    if (limit && !validator.isInt(limit, { min: 1, max: 100 })) {
      return res.status(400).json({ error: 'Invalid limit parameter' });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const resultLimit = limit ? parseInt(limit) : users.length;
    res.json(users.slice(0, resultLimit));
  } catch (error) {
    console.error('Error in /users endpoint:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ============ ERROR HANDLING ============

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't expose error details in production
  const isDevelopment = process.env.NODE_ENV === 'development';
  const message = isDevelopment ? err.message : 'Internal server error';

  res.status(err.status || 500).json({ 
    error: message,
    ...(isDevelopment && { stack: err.stack })
  });
});

// ============ SERVER ============

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

module.exports = app;
```

